(function($) {
'use strict';
$('#vh360_push_run_validation').on('click', function() {
var btn = $(this);
var statusSpan = $('#vh360-validation-status');
btn.prop('disabled', true).text('Running validation...');
statusSpan.html('');
$.ajax({
url: VH360PushAdmin.ajaxurl,
type: 'POST',
data: {
action: 'vh360_pwa_push_run_validation',
nonce: VH360PushAdmin.nonce
},
success: function(response) {
if (response.success) {
statusSpan.html('<span style="color: #46b450;">✓ ' + response.data.message + '</span>');
if (response.data.results) {
$.each(response.data.results, function(key, result) {
var item = $('.vh360-validation-item[data-item="' + key + '"]');
if (item.length) {
item.removeClass('pending passed failed');
if (result.passed) {
item.addClass('passed');
item.find('.vh360-validation-icon').text('✅');
item.find('.vh360-validation-details').remove();
} else {
item.addClass('failed');
item.find('.vh360-validation-icon').text('❌');
var detailsDiv = item.find('.vh360-validation-details');
if (detailsDiv.length) {
detailsDiv.text(result.error || '');
} else if (result.error) {
var newDetailsDiv = $('<div class="vh360-validation-details"></div>').text(result.error);
item.find('div').append(newDetailsDiv);
}
}
}
});
}
setTimeout(function() {
window.location.reload();
}, 2000);
} else {
statusSpan.html('<span style="color: #dc3232;">✗ ' + (response.data.message || 'Validation failed') + '</span>');
}
},
error: function() {
statusSpan.html('<span style="color: #dc3232;">✗ Network error. Please try again.</span>');
},
complete: function() {
btn.prop('disabled', false).text('Run Full Validation');
}
});
});
$('#vh360_push_send_test_btn').on('click', function() {
var btn = $(this);
var title = $('#vh360_push_test_title').val();
var body = $('#vh360_push_test_body').val();
var resultDiv = $('#vh360-push-test-result');
if (!title || !body) {
resultDiv.html('<div class="notice notice-error"><p>Title and body are required.</p></div>');
return;
}
btn.prop('disabled', true).text('Sending...');
resultDiv.html('');
$.ajax({
url: VH360PushAdmin.ajaxurl,
type: 'POST',
data: {
action: 'vh360_pwa_push_send_test',
nonce: VH360PushAdmin.nonce,
title: title,
body: body
},
success: function(response) {
if (response.success) {
resultDiv.html('<div class="notice notice-success"><p>' + response.data.message + '</p></div>');
} else {
resultDiv.html('<div class="notice notice-error"><p>' + (response.data.message || 'Failed to send test notification.') + '</p></div>');
}
},
error: function() {
resultDiv.html('<div class="notice notice-error"><p>Network error. Please try again.</p></div>');
},
complete: function() {
btn.prop('disabled', false).text('Send Test Push');
}
});
});
$('#vh360_push_send_btn').on('click', function() {
if (!confirm('Are you sure you want to send this notification to all subscribers?')) {
return;
}
var btn = $(this);
var title = $('#vh360_push_send_title').val();
var body = $('#vh360_push_send_body').val();
var url = $('#vh360_push_send_url').val();
var resultDiv = $('#vh360-push-send-result');
if (!title || !body) {
resultDiv.html('<div class="notice notice-error"><p>Title and body are required.</p></div>');
return;
}
btn.prop('disabled', true).text('Sending...');
resultDiv.html('');
$.ajax({
url: VH360PushAdmin.ajaxurl,
type: 'POST',
data: {
action: 'vh360_pwa_push_send',
nonce: VH360PushAdmin.nonce,
title: title,
body: body,
url: url
},
success: function(response) {
if (response.success) {
resultDiv.html('<div class="notice notice-success"><p><strong>' + response.data.message + '</strong></p></div>');
$('#vh360_push_send_title').val('');
$('#vh360_push_send_body').val('');
} else {
resultDiv.html('<div class="notice notice-error"><p>' + (response.data.message || 'Failed to send notification.') + '</p></div>');
}
},
error: function() {
resultDiv.html('<div class="notice notice-error"><p>Network error. Please try again.</p></div>');
},
complete: function() {
btn.prop('disabled', false).text('Send Notification');
}
});
});
})(jQuery);
